    );
  }

  created() {
    if (!this.admin || this.admin.role !== "ADMIN") {
      delete this.creationBot.partnerUserIds;
    }
  }

  get creationBotVariables() {
    return Object.keys(this.creationBot).reduce((acc, c) => {
      acc[c] = this.creationBot[c].value;
